```javascript
/** @type {import('next').NextConfig} */
const nextConfig = {
  experimental: {
    serverComponentsExternalPackages: ['path', 'net'],
  },
  webpack: (config, { isServer }) => {
    if (isServer) {
      config.externals = [
        ...(config.externals || []),
        'fs/promises',
        'path',
        'crypto',
        'sharp',
      ];
    }
    return config;
  },
};

module.exports = nextConfig;
```

