```javascript
/** @type {import('next').NextConfig} */
const nextConfig = {
  experimental: {
    serverComponentsExternalPackages: [],
  },
  webpack: (config, { isServer }) => {
    if (isServer) {
      config.externals = [
        ...(config.externals || []),
        'crypto',
        'child_process',
        'events',
        'zlib',
        'stream',
      ];
    }
    return config;
  },
};

export default nextConfig;
```

